  ('judicial-57112235-moex-00569', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關正義模式（JusticeModel）對少年司法體系之主張，下列敘述何者錯誤？', '["少年犯之處遇應逐漸經由轉向計畫走向自願性服務性質的特色", "少年司法體系工作人員之自由裁量不應予以限制，以促使矯治措施之踐行", "少年法庭不定期刑之使用應予以禁止", "對少年犯應多科以損害賠償及社區服務，以提供其贖罪及賠償的機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00570', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '美國自1960年代中期開始，受刑人權利因各級法院介入而獲改善，直至1980年開始進入限縮干 預政策時代，不再漫無限制的開放與擴充受刑人權利，導致如此改變之因素，下列何者錯誤？', '["受寬鬆刑事政策影響", "管教人員經常因案涉訟，影響工作", "受刑人之訴訟案件逐年大幅攀升", "此時期的大法官以保守派居多"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00571', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關矯正人員應有的專業倫理與人權觀念的敘述，下列何者正確？', '["矯正人員應嚴守行政中立，不得利用職權要求收容人支持特定政黨，但得基於宗教教誨之目的， 強制收容人信仰特定宗教", "矯正人員在不為自己謀取任何利益之立場下，得利用職務之便，向收容人及收容人親友媒介與 推銷自己親友經營之商業", "我國雖非聯合國會員國，但公民與政治權利國際公約在我國已具有國內法律之效力，有關該公 約禁止酷刑或不人道刑罰等相關條文，在我國亦適用", "受刑人就監獄處分或其他管理措施有所不服，依司法院釋字第755號受刑人司法救濟案之解釋 意旨，只能依申訴、再申訴請求救濟，尚無行政訴訟之適用 20720"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00572', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄作業，下列敘述何者錯誤？', '["我國監獄作業種類分監內作業、監外作業、視同作業（準作業）", "我國監獄作業的目標是以委託加工為主，自營作業為輔", "監獄作業制度中與民間企業有關聯的涵蓋：合約業制、委託業制、租賃業制", "監獄作業制度中與民間企業無關聯的涵蓋：國營業制、官用業制、公共事業制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00573', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關外役監受刑人遴選條件之敘述，下列何者錯誤？', '["受有期徒刑之執行逾1個月", "刑期7年以下，或刑期逾7年未滿15年而累進處遇進至第三級以上", "刑期15年以上而累進處遇進至第二級以上", "無期徒刑累進處遇應進至第一級"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00574', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關改進我國假釋制度缺失之對策，下列敘述何者錯誤？', '["強化假釋審核機制", "建構本土化假釋再犯風險預測量表", "從嚴從實考核累進處遇成績", "配合減刑條例之規定，應定期實施減刑，減少假釋之比例，以防被濫用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00575', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '內觀法在矯正機構之應用以日本最具成效，有關內觀法施行重點之敘述，下列何者錯誤？', '["藉著隔離以減少外界之刺激，維持良好的靜思環境", "以自責式思考自我行為省察，激發感謝他人之念頭", "拋棄本位主義，以理性、同情心之原則為行動依據", "強調激發對父親之愧疚心與罪惡感，矢志反哺親恩"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00576', 'judicial-57112235', 'judicial-57112235-moex-111-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於目前我國矯正機構面臨之問題的敘述，下列何者錯誤？', '["醫療及戒護人力不足，影響工作之品質", "重刑化刑事政策下導致高齡與長刑期受刑人處遇問題漸漸浮現", "受刑人尚未加入全民健康保險，面臨嚴重之醫療人權問題", "監獄受刑人超額收容問題，導致監獄擁擠現象仍待持續解決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "726b27a1a90d", "answer_pdf_sha1": "a7721ff1b3e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
